function solve(nums) {
  const n = nums.length;
  for (let p = 1; p < n - 1; p++) {
    let valid = true;
    for (let i = 0; i < p; i++) {
      if (nums[i] >= nums[i + 1]) {
        valid = false;
        break;
      }
    }
    if (!valid) continue;
    for (let q = p + 1; q < n - 1; q++) {
      valid = true;
      for (let i = p; i < q; i++) {
        if (nums[i] <= nums[i + 1]) {
          valid = false;
          break;
        }
      }
      if (!valid) continue;
      valid = true;
      for (let i = q; i < n - 1; i++) {
        if (nums[i] >= nums[i + 1]) {
          valid = false;
          break;
        }
      }
      if (valid) return true;
    }
  }
  return false;
}
